    return await db
      .select()
      .from(leaveRequests)
      .where(eq(leaveRequests.employeeId, employeeId))
      .orderBy(desc(leaveRequests.createdAt));
  }

  async getAllLeaveRequests(): Promise<LeaveRequest[]> {
    return await db.select().from(leaveRequests).orderBy(desc(leaveRequests.createdAt));
  }

  async createLeaveRequest(insertRequest: InsertLeaveRequest): Promise<LeaveRequest> {
    const [request] = await db
      .insert(leaveRequests)
      .values(insertRequest)
      .returning();
    return request;
  }

  async updateLeaveRequest(id: string, updateRequest: Partial<LeaveRequest>): Promise<LeaveRequest> {
    const [request] = await db
      .update(leaveRequests)
      .set(updateRequest)
      .where(eq(leaveRequests.id, id))
      .returning();
    return request;
  }

  async deleteLeaveRequest(id: string): Promise<void> {
    await db.delete(leaveRequests).where(eq(leaveRequests.id, id));
  }

  // Attendance
  async getAttendance(id: string): Promise<Attendance | undefined> {
    const [attendance] = await db.select().from(attendance).where(eq(attendance.id, id));
    return attendance || undefined;
  }

  async getAttendanceByEmployee(employeeId: string, startDate?: Date, endDate?: Date): Promise<Attendance[]> {
    let conditions = [eq(attendance.employeeId, employeeId)];

    if (startDate && endDate) {
      conditions.push(
        gte(attendance.date, startDate),
        lte(attendance.date, endDate)
      );
    }

    return await db.select().from(attendance)
      .where(and(...conditions))
      .orderBy(desc(attendance.date));
  }

  async getAllAttendance(): Promise<Attendance[]> {
    return await db.select().from(attendance).orderBy(desc(attendance.date));
  }

  async createAttendance(insertAttendance: InsertAttendance): Promise<Attendance> {
    const [record] = await db
      .insert(attendance)
      .values(insertAttendance)
      .returning();
    return record;
  }

  async updateAttendance(id: string, updateAttendance: Partial<InsertAttendance>): Promise<Attendance> {
    const [record] = await db
      .update(attendance)
      .set(updateAttendance)
      .where(eq(attendance.id, id))
      .returning();
    return record;
  }

  async deleteAttendance(id: string): Promise<void> {
    await db.delete(attendance).where(eq(attendance.id, id));
  }

  // Dashboard Stats
  async getDashboardStats(): Promise<any> {
    const [totalEmployees] = await db.select({ count: sql<number>`count(*)` }).from(employees);
    const [totalPayroll] = await db.select({ 
      total: sql<number>`COALESCE(sum(${payrolls.netSalary}), 0)` 
    }).from(payrolls);
    const [pendingLeaves] = await db.select({ count: sql<number>`count(*)` })
      .from(leaveRequests)
      .where(eq(leaveRequests.status, 'pending'));
    const [presentToday] = await db.select({ count: sql<number>`count(*)` })
      .from(attendance)
      .where(and(
        eq(attendance.status, 'present'),
        gte(attendance.date, new Date(new Date().toDateString()))
      ));

    return {
      totalEmployees: totalEmployees?.count || 0,
      totalPayroll: totalPayroll?.total || 0,
      pendingLeaves: pendingLeaves?.count || 0,
      presentToday: presentToday?.count || 0,
    };
  }

  async getEmployeeDashboardStats(employeeId: string): Promise<any> {
    const employee = await this.getEmployee(employeeId);
    const leaveRequests = await this.getLeaveRequestsByEmployee(employeeId);
    const attendanceRecords = await this.getAttendanceByEmployee(employeeId, 
      new Date(new Date().getFullYear(), new Date().getMonth(), 1),
      new Date()
    );

    const pendingRequests = leaveRequests.filter(req => req.status === 'pending').length;
    const presentDays = attendanceRecords.filter(rec => rec.status === 'present').length;
    const totalDays = attendanceRecords.length;
    const attendanceRate = totalDays > 0 ? (presentDays / totalDays) * 100 : 0;

    // Calculate leave balance (assuming 30 days annual leave)
    const usedLeaves = leaveRequests
      .filter(req => req.status === 'approved')
      .reduce((sum, req) => sum + req.days, 0);
    const leaveBalance = 30 - usedLeaves;

    return {
      currentSalary: employee?.salary || 0,
      leaveBalance,
      attendanceRate: Math.round(attendanceRate * 10) / 10,
      pendingRequests,
    };
  }
}

export const storage = new DatabaseStorage();

