import { useState } from "react";
import { useAuth } from "@/hooks/use-auth";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useLocation } from "wouter";
import { Sidebar } from "@/components/layout/sidebar";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { Plus, Search, Check, X } from "lucide-react";
import type { LeaveRequest, Employee } from "@shared/schema";

export default function LeaveRequests() {
  const { user } = useAuth();
  const [, setLocation] = useLocation();
  const [searchTerm, setSearchTerm] = useState("");

  const { data: leaveRequests, isLoading: requestsLoading } = useQuery<LeaveRequest[]>({
    queryKey: ["/api/leave-requests"],
  });

  const { data: employees, isLoading: employeesLoading } = useQuery<Employee[]>({
    queryKey: ["/api/employees"],
    enabled: user?.role === 'admin',
  });

  const updateLeaveRequestMutation = useMutation({
    mutationFn: async ({ id, status }: { id: string; status: 'approved' | 'rejected' }) => {
      const response = await apiRequest("PUT", `/api/leave-requests/${id}`, { status });
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/leave-requests"] });
    },
  });

  const getEmployeeName = (employeeId: string) => {
    const employee = employees?.find(emp => emp.id === employeeId);
    return employee ? `${employee.firstName} ${employee.lastName}` : 'Unknown Employee';
  };

  const filteredRequests = leaveRequests?.filter(request => {
    const searchLower = searchTerm.toLowerCase();
    const employeeName = getEmployeeName(request.employeeId).toLowerCase();
    return (
      employeeName.includes(searchLower) ||
      request.leaveType.toLowerCase().includes(searchLower) ||
      request.reason?.toLowerCase().includes(searchLower)
    );
  }) || [];

  const handleApproveRequest = (id: string) => {
    updateLeaveRequestMutation.mutate({ id, status: 'approved' });
  };

  const handleRejectRequest = (id: string) => {
    updateLeaveRequestMutation.mutate({ id, status: 'rejected' });
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric'
    });
  };

  if (requestsLoading || (user?.role === 'admin' && employeesLoading)) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
      </div>
    );
  }

  return (
    <div className="flex min-h-screen bg-gray-50" data-testid="leave-requests-page">
      <Sidebar userRole={user?.role || 'employee'} />

      <div className="flex-1 ml-64">
        {/* Header */}
        <header className="bg-white shadow-sm border-b p-6">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-2xl font-bold text-gray-900" data-testid="text-page-title">
                {user?.role === 'admin' ? 'Leave Requests Management' : 'My Leave Requests'}
              </h1>
              <p className="text-gray-600 mt-1" data-testid="text-page-description">
                {user?.role === 'admin' 
                  ? 'Review and manage employee leave requests' 
                  : 'View your leave request history'
                }
              </p>
            </div>
            {user?.role === 'employee' && (
              <Button
                onClick={() => setLocation("/leaves/apply")}
                data-testid="button-apply-leave"
              >
                <Plus className="h-4 w-4 mr-2" />
                Apply for Leave
              </Button>
            )}
          </div>
        </header>

        {/* Content */}
        <main className="p-6">
          <Card data-testid="card-leave-requests">
            <CardHeader>
              <div className="flex items-center justify-between">
                <CardTitle data-testid="text-requests-title">
                  {user?.role === 'admin' ? 'All Leave Requests' : 'Your Leave Requests'}
                </CardTitle>
                <div className="flex items-center space-x-2">
                  <div className="relative">
                    <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 h-4 w-4" />
                    <Input
                      placeholder="Search requests..."
                      value={searchTerm}
                      onChange={(e) => setSearchTerm(e.target.value)}
                      className="pl-10 w-64"
                      data-testid="input-search-requests"
                    />
                  </div>
                </div>
              </div>
            </CardHeader>
            <CardContent>
              <div className="overflow-x-auto">
                <table className="w-full" data-testid="table-leave-requests">
                  <thead className="bg-gray-50 border-b">
                    <tr>
                      {user?.role === 'admin' && (
                        <th className="text-left py-3 px-6 font-medium text-gray-700">Employee</th>
                      )}
                      <th className="text-left py-3 px-6 font-medium text-gray-700">Leave Type</th>
                      <th className="text-left py-3 px-6 font-medium text-gray-700">Start Date</th>
                      <th className="text-left py-3 px-6 font-medium text-gray-700">End Date</th>
                      <th className="text-left py-3 px-6 font-medium text-gray-700">Days</th>
                      <th className="text-left py-3 px-6 font-medium text-gray-700">Reason</th>
                      <th className="text-left py-3 px-6 font-medium text-gray-700">Status</th>
                      {user?.role === 'admin' && (
                        <th className="text-left py-3 px-6 font-medium text-gray-700">Actions</th>
                      )}
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-200">
                    {filteredRequests.map((request) => (
                      <tr key={request.id} className="hover:bg-gray-50" data-testid={`row-request-${request.id}`}>
                        {user?.role === 'admin' && (
                          <td className="py-4 px-6" data-testid={`text-employee-${request.id}`}>
                            {getEmployeeName(request.employeeId)}
                          </td>
                        )}
                        <td className="py-4 px-6" data-testid={`text-leave-type-${request.id}`}>
                          <span className="capitalize">{request.leaveType}</span>
                        </td>
                        <td className="py-4 px-6 text-gray-700" data-testid={`text-start-date-${request.id}`}>
                          {formatDate(request.startDate.toString())}
                        </td>
                        <td className="py-4 px-6 text-gray-700" data-testid={`text-end-date-${request.id}`}>
                          {formatDate(request.endDate.toString())}
                        </td>
                        <td className="py-4 px-6 text-gray-700" data-testid={`text-days-${request.id}`}>
                          {request.days}
                        </td>
                        <td className="py-4 px-6 text-gray-700 max-w-xs truncate" data-testid={`text-reason-${request.id}`}>
                          {request.reason || 'No reason provided'}
                        </td>
                        <td className="py-4 px-6">
                          <Badge 
                            variant={
                              request.status === 'approved' ? 'default' : 
                              request.status === 'rejected' ? 'destructive' : 'secondary'
                            }
                            data-testid={`badge-status-${request.id}`}
                          >
                            {request.status}
                          </Badge>
                        </td>
                        {user?.role === 'admin' && (
                          <td className="py-4 px-6">
                            {request.status === 'pending' && (
                              <div className="flex items-center space-x-2">
                                <Button
                                  variant="outline"
                                  size="sm"
                                  onClick={() => handleApproveRequest(request.id)}
                                  disabled={updateLeaveRequestMutation.isPending}
                                  data-testid={`button-approve-${request.id}`}
                                  className="text-green-600 border-green-600 hover:bg-green-50"
                                >
                                  <Check className="h-4 w-4" />
                                </Button>
                                <Button
                                  variant="outline"
                                  size="sm"
                                  onClick={() => handleRejectRequest(request.id)}
                                  disabled={updateLeaveRequestMutation.isPending}
                                  data-testid={`button-reject-${request.id}`}
                                  className="text-red-600 border-red-600 hover:bg-red-50"
                                >
                                  <X className="h-4 w-4" />
                                </Button>
                              </div>
                            )}
                            {request.status !== 'pending' && (
                              <span className="text-sm text-gray-500">
                                {request.status === 'approved' ? 'Approved' : 'Rejected'}
                              </span>
                            )}
                          </td>
                        )}
                      </tr>
                    ))}
                  </tbody>
                </table>

                {filteredRequests.length === 0 && (
                  <div className="text-center py-8 text-gray-500" data-testid="text-no-requests">
                    {searchTerm ? 'No leave requests found matching your search.' : 'No leave requests found.'}
                  </div>
                )}
              </div>
            </CardContent>
          </Card>
        </main>
      </div>
    </div>
  );
}

client/src/pages/payroll/add-payroll.tsx.content:
import { useEffect } from 'react';
import { useAuth } from "@/hooks/use-auth";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useLocation, Redirect } from "wouter";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { Sidebar } from "@/components/layout/sidebar";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { insertPayrollSchema, type InsertPayroll, type Employee } from "@shared/schema";
import { ArrowLeft } from "lucide-react";

export default function AddPayroll() {
  const { user } = useAuth();
  const [, setLocation] = useLocation();

  if (user?.role !== 'admin') {
    return <Redirect to="/" />;
  }

  const { data: employees, isLoading: employeesLoading } = useQuery<Employee[]>({
    queryKey: ["/api/employees"],
  });

  const form = useForm<InsertPayroll>({
    resolver: zodResolver(insertPayrollSchema),
    defaultValues: {
      employeeId: "",
      payPeriod: "",
      baseSalary: "",
      allowances: "0",
      deductions: "0",
      netSalary: "",
      status: "pending",
    },
  });

  const baseSalary = form.watch("baseSalary");
  const allowances = form.watch("allowances");
  const deductions = form.watch("deductions");

  // Calculate net salary automatically
  useEffect(() => {
    const base = parseFloat(baseSalary || "0");
    const allow = parseFloat(allowances || "0");
    const deduct = parseFloat(deductions || "0");
    const net = base + allow - deduct;

    if (!isNaN(net) && net >= 0) {
      form.setValue("netSalary", net.toString());
    }
  }, [baseSalary, allowances, deductions, form]);

  const addPayrollMutation = useMutation({
    mutationFn: async (data: InsertPayroll) => {
      const response = await apiRequest("POST", "/api/payrolls", data);
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/payrolls"] });
      setLocation("/payroll");
    },
  });

  const onSubmit = (data: InsertPayroll) => {
    addPayrollMutation.mutate(data);
  };

  if (employeesLoading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
      </div>
    );
  }

  return (
    <div className="flex min-h-screen bg-gray-50" data-testid="add-payroll-page">
      <Sidebar userRole="admin" />

      <div className="flex-1 ml-64">
        {/* Header */}
        <header className="bg-white shadow-sm border-b p-6">
          <div className="flex items-center space-x-4">
            <Button
              variant="ghost"
              onClick={() => setLocation("/payroll")}
              data-testid="button-back"
            >
              <ArrowLeft className="h-4 w-4" />
            </Button>
            <div>
              <h1 className="text-2xl font-bold text-gray-900" data-testid="text-page-title">
                Add New Payroll
              </h1>
              <p className="text-gray-600 mt-1" data-testid="text-page-description">
                Create a new payroll record
              </p>
            </div>
          </div>
        </header>

        {/* Content */}
        <main className="p-6">
          <div className="max-w-2xl">
            <Card data-testid="card-add-payroll-form">
              <CardHeader>
                <CardTitle data-testid="text-form-title">Payroll Information</CardTitle>
              </CardHeader>
              <CardContent>
                <Form {...form}>
                  <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6" data-testid="form-add-payroll">
                    <FormField
                      control={form.control}
                      name="employeeId"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel data-testid="label-employee">Employee</FormLabel>
                          <Select onValueChange={field.onChange} value={field.value} data-testid="select-employee">
                            <FormControl>
                              <SelectTrigger>
                                <SelectValue placeholder="Select employee" />
                              </SelectTrigger>
                            </FormControl>
                            <SelectContent>
                              {employees?.map((employee) => (
                                <SelectItem key={employee.id} value={employee.id}>
                                  {employee.firstName} {employee.lastName} - {employee.department}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={form.control}
                      name="payPeriod"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel data-testid="label-pay-period">Pay Period</FormLabel>
                          <FormControl>
                            <Input
                              placeholder="e.g., March 2024, 2024-03"
                              data-testid="input-pay-period"
                              {...field}
                            />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={form.control}
                      name="baseSalary"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel data-testid="label-base-salary">Base Salary</FormLabel>
                          <FormControl>
                            <Input
                              type="number"
                              step="0.01"
                              placeholder="Enter base salary"
                              data-testid="input-base-salary"
                              {...field}
                            />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <div className="grid grid-cols-2 gap-4">
                      <FormField
                        control={form.control}
                        name="allowances"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel data-testid="label-allowances">Allowances</FormLabel>
                            <FormControl>
                              <Input
                                type="number"
                                step="0.01"
                                placeholder="Enter allowances"
                                data-testid="input-allowances"
                                {...field}
                                value={field.value || ''}
                              />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />

                      <FormField
                        control={form.control}
                        name="deductions"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel data-testid="label-deductions">Deductions</FormLabel>
                            <FormControl>
                              <Input
                                type="number"
                                step="0.01"
                                placeholder="Enter deductions"
                                data-testid="input-deductions"
                                {...field}
                                value={field.value || ''}
                              />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                    </div>

                    <FormField
                      control={form.control}
                      name="netSalary"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel data-testid="label-net-salary">Net Salary</FormLabel>
                          <FormControl>
                            <Input
                              type="number"
                              step="0.01"
                              placeholder="Net salary (calculated automatically)"
                              data-testid="input-net-salary"
                              readOnly
                              className="bg-gray-50"
                              {...field}
                            />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={form.control}
                      name="payDate"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel data-testid="label-pay-date">Pay Date (Optional)</FormLabel>
                          <FormControl>
                            <Input
                              type="date"
                              data-testid="input-pay-date"
                              value={field.value ? new Date(field.value).toISOString().split('T')[0] : ''}
                              onChange={(e) => field.onChange(e.target.value ? new Date(e.target.value) : undefined)}
                            />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={form.control}
                      name="status"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel data-testid="label-status">Status</FormLabel>
                          <Select onValueChange={field.onChange} defaultValue={field.value} data-testid="select-status">
                            <FormControl>
                              <SelectTrigger>
                                <SelectValue placeholder="Select status" />
                              </SelectTrigger>
                            </FormControl>
                            <SelectContent>
                              <SelectItem value="pending">Pending</SelectItem>
                              <SelectItem value="paid">Paid</SelectItem>
                            </SelectContent>
                          </Select>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <div className="flex items-center space-x-4 pt-4">
                      <Button
                        type="submit"
                        disabled={addPayrollMutation.isPending}
                        data-testid="button-save-payroll"
                      >
                        {addPayrollMutation.isPending ? "Saving..." : "Save Payroll"}
                      </Button>
                      <Button
                        type="button"
                        variant="outline"
                        onClick={() => setLocation("/payroll")}
                        data-testid="button-cancel"
                      >
                        Cancel
                      </Button>
                    </div>
                  </form>
                </Form>
              </CardContent>
            </Card>
          </div>
        </main>
      </div>
    </div>
  );
}

